以下是一个简单的示例代码，实现了全景数据和点云数据的切换效果：

HTML代码：
```html
<!DOCTYPE html>
<html>
  <head>
    <meta charset="utf-8">
    <title>Panorama and Point Cloud Example</title>
    <style>
      body { margin: 0; }
      canvas { width: 100%; height: 100%; }
    </style>
  </head>
  <body>
    <script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/110/three.min.js"></script>
    <script src="your-panorama-data.js"></script>
    <script src="your-point-cloud-data.js"></script>
    <script src="main.js"></script>
  </body>
</html>
```

your-panorama-data.js:
```javascript
var panoramaData = "your-panorama-data.png"; // 全景数据的URL
```

your-point-cloud-data.js:
```javascript
var pointCloudData = [
  { position: [x1, y1, z1], color: 0xffffff }, // 点云数据的点的位置和颜色
  { position: [x2, y2, z2], color: 0xff0000 },
  // ...
];
```

main.js:
```javascript
var scene, camera, renderer;
var currentData = 'panorama'; // 当前显示的数据，初始为全景数据

// 初始化函数
function init() {
  scene = new THREE.Scene();

  // 创建全景球体
  var panoramaTexture = new THREE.TextureLoader().load(panoramaData);
  panoramaTexture.mapping = THREE.EquirectangularRefractionMapping;
  var panoramaGeometry = new THREE.SphereGeometry(100, 32, 32); // 球体的大小和分段数根据实际情况设置
  var panoramaMaterial = new THREE.MeshBasicMaterial({ map: panoramaTexture, side: THREE.DoubleSide });
  var panoramaMesh = new THREE.Mesh(panoramaGeometry, panoramaMaterial);
  scene.add(panoramaMesh);

  // 创建点云
  var pointCloudGeometry = new THREE.Geometry();
  pointCloudData.forEach(function(point){
    var vertex = new THREE.Vector3(point.position[0], point.position[1], point.position[2]);
    pointCloudGeometry.vertices.push(vertex);
    pointCloudGeometry.colors.push(new THREE.Color(point.color));
  });
  var pointCloudMaterial = new THREE.PointsMaterial({ size: 1, vertexColors: THREE.VertexColors });
  var pointCloud = new THREE.Points(pointCloudGeometry, pointCloudMaterial);
  scene.add(pointCloud);

  // 创建相机
  camera = new THREE.PerspectiveCamera(75, window.innerWidth / window.innerHeight, 0.1, 1000)
  camera.position.set(0, 0, 0);

  // 创建渲染器
  renderer = new THREE.WebGLRenderer();
  renderer.setSize(window.innerWidth, window.innerHeight);
  document.body.appendChild(renderer.domElement);

  // 添加交互控制
  var controls = new THREE.OrbitControls(camera, renderer.domElement);

  // 监听窗口大小变化
  window.addEventListener('resize', onWindowResize, false);
}

// 窗口大小变化回调函数
function onWindowResize() {
  camera.aspect = window.innerWidth / window.innerHeight;
  camera.updateProjectionMatrix();
  renderer.setSize(window.innerWidth, window.innerHeight);
}

// 切换数据函数
function toggleData() {
  if (currentData === 'panorama') {
    scene.children[0].visible = false; // 隐藏全景球体
    scene.children[1].visible = true; // 显示点云
    currentData = 'pointCloud';
  } else {
    scene.children[0].visible = true; // 显示全景球体
    scene.children[1].visible = false; // 隐藏点云
    currentData = 'panorama';
  }
}

// 渲染函数
function animate() {
  requestAnimationFrame(animate);
  renderer.render(scene, camera);
}

// 初始化并开始渲染
init();
animate();
```

以上代码假设你有一张全景数据图片(png格式)，以及一个点云数据数组(pointCloudData)，其中点云数据是一个包含了位置和颜色的对象数组。在切换数据时，通过toggleData()函数进行切换显示效果。

注意，上述代码仅作为示例，具体实现会根据你的具体需求和数据格式进行调整。

要使用Potree库来加载点云数据并与全景数据一起显示，你需要按照以下步骤进行操作：

1. 下载Potree库：你可以从Potree的GitHub仓库（https://github.com/potree/potree）上下载完整的Potree库。

2. 准备点云数据：将点云数据准备成Potree支持的格式，通常是以LAS或LAZ格式的点云文件。你可以使用Potree的Converter工具将点云数据转换为Potree格式。例如，你可以使用Potree Converter命令行工具来转换点云数据：

```bash
potree_converter.exe --generate-page NAME_OF_OUTPUT_FOLDER INPUT_FILE.las
```

该命令将会生成一个包含了转换后点云数据的文件夹，其中包括HTML、JS和数据文件。

3. 准备全景数据：你需要准备一个全景图片或多张图片来作为全景数据。可以使用全景格式如equirectangular或cubemap，根据你的需求选择相应的格式。

4. 创建HTML文件：创建一个HTML文件，用于加载和显示全景和点云数据。以下是一个简单的示例：

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Potree Point Cloud and Panorama Example</title>
  <style>
    body { margin: 0; overflow: hidden; }
    #potree_container { position: fixed; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; }
    #panorama_container { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background-color: black; }
    canvas { width: 100%; height: 100%; }
  </style>
</head>
<body>
  <div id="potree_container"></div>
  <div id="panorama_container"></div>

  <script src="potree/build/potree/potree.min.js"></script>
  <script src="your-potree-folder/viewer.js"></script>
  <script src="your-panorama-library.js"></script>

  <script>
    var viewer = new Potree.Viewer("#potree_container");
    viewer.setEDLEnabled(false);
    viewer.loadSettingsFromURL();
    viewer.setDescription("Potree Point Cloud");
    viewer.setPointBudget(1e6);

    Potree.loadPointCloud("your-potree-folder/cloud.js", "Potree Point Cloud", function(d){
      viewer.scene.addPointCloud(d.pointcloud);
      viewer.moveTo(PointCloud);
    });

    var panoramaViewer = new PANOLENS.Viewer({ output: 'panoramaContainer', cameraFov: 90, container: document.querySelector('#panorama_container') });
    var panorama = new PANOLENS.ImagePanorama("your-panorama.jpg");
    panoramaViewer.add(panorama);
  </script>
</body>
</html>
```

- 在文件中，你需要修改`potree.min.js`的路径和`viewer.js`的路径为你下载并放置Potree库的实际路径。
- 同样地，你需要修改`your-potree-folder/cloud.js`的路径为你转换后的Potree格式点云数据的文件路径。
- 你还需要修改`your-panorama.jpg`的路径为你的全景数据文件路径。

5. 打开HTML文件：在任意Web服务器上打开该HTML文件，你将会看到加载并显示了全景数据和点云数据的效果。

以上示例中，Potree库用于加载和显示点云数据，PANOLENS库用于加载和显示全景数据。通过Potree的Viewer和PointCloud对象来实现点云数据的加载和显示，并通过PANOLENS的Viewer和ImagePanorama对象实现全景数据的加载和显示。

要实现Potree加载点云数据和全景图之间的切换，你可以按照以下步骤进行操作：

1. 创建HTML文件：创建一个HTML文件，用于加载和显示Potree点云数据和全景图。以下是一个简单的示例：

```html
<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <title>Potree Point Cloud and Panorama Example</title>
  <style>
    body { margin: 0; overflow: hidden; }
    #potree_container { position: fixed; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; }
    #panorama_container { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background-color: black; }
    canvas { width: 100%; height: 100%; }
  </style>
